#include "ai_factory/cuda/cir/interest_rate_swaps.cuh"
#include "ai_factory/common/fixed_income/cir.hpp"
#include "ai_factory/cuda/common/runtime.cuh"
namespace ai_factory::cuda {namespace{struct WorkspaceTag{};__global__ void kernel(const CirSwapRow* rows,std::size_t count,MonteCarloOutput* out){const std::size_t i=blockIdx.x*blockDim.x+threadIdx.x;if(i>=count)return;const auto row=rows[i];const auto&m=row.model;const auto&p=row.product;double annuity=0;for(int j=1;j<=p.payment_count;++j)annuity+=p.accrual_period*fixed_income::cir_bond_price(m.initial_rate,m.kappa,m.theta,m.volatility,p.start_time+j*p.accrual_period);const double end=p.start_time+p.payment_count*p.accrual_period;const double value=p.notional*static_cast<double>(p.direction)*(fixed_income::cir_bond_price(m.initial_rate,m.kappa,m.theta,m.volatility,p.start_time)-fixed_income::cir_bond_price(m.initial_rate,m.kappa,m.theta,m.volatility,end)-p.fixed_rate*annuity);out[i]={value,0.0};}}
void price_cir_interest_rate_swap_cuda(const CirSwapRow* host,std::size_t count,MonteCarloOutput*out,CudaTiming*t){auto&w=detail::reusable_cuda_workspace<WorkspaceTag,2>();auto*r=w.buffer<CirSwapRow>(0,count,"cudaMalloc rows");auto*o=w.buffer<MonteCarloOutput>(1,count,"cudaMalloc outputs");detail::check_cuda(cudaMemcpy(r,host,count*sizeof(*host),cudaMemcpyHostToDevice),"copy rows");auto a=w.start_event(),b=w.stop_event();detail::check_cuda(cudaEventRecord(a),"event");kernel<<<static_cast<unsigned>((count+255)/256),256>>>(r,count,o);detail::check_cuda(cudaGetLastError(),"CIR swap kernel");detail::check_cuda(cudaEventRecord(b),"event");detail::check_cuda(cudaEventSynchronize(b),"sync");float ms=0;detail::check_cuda(cudaEventElapsedTime(&ms,a,b),"elapsed");detail::check_cuda(cudaMemcpy(out,o,count*sizeof(*out),cudaMemcpyDeviceToHost),"copy outputs");if(t){t->simulation_ms=ms;t->total_ms=ms;}}
}
